    // RET NZ
    private static int RET_NZ(Z80InstructionEmulator emulator, Action<ActionRequired, ushort, byte> onActionRequired)
    {
        if ((emulator.F & 0b01000000) == 0b01000000 /* !condition.NZ */)
        {
            return emulator.CompleteInstruction(false, 1);
        }

        emulator.address = emulator.SP;
        emulator.SP += 0x01;
        onActionRequired(ActionRequired.MemoryRead, emulator.address, emulator.data);
        emulator.Z = emulator.data;
        emulator.address = emulator.SP;
        emulator.SP += 0x01;
        onActionRequired(ActionRequired.MemoryRead, emulator.address, emulator.data);
        emulator.W = emulator.data;
        emulator.PC = emulator.WZ;
        return emulator.CompleteInstruction(false, 7);
    }

