        flags |= (left ^ right ^ result) & 0b00010000; // Set H if did_8_bit_subtraction_half_borrow(left, right, result) is true.
        flags |= (Unsafe.BitCast<bool, byte>(result == 0)) << 6; // Set Z if is_zero(result) is true.
        emulator.F = (byte)flags;
        return emulator.CompleteInstruction(true, 11);
    }

    // FDCB Redirect
    private static int FDCB_Redirect(Z80InstructionEmulator emulator, Action<ActionRequired, ushort, byte> onActionRequired)
    {
        emulator.opcodeStepTable = OpcodeStepTableNoPrefix;
        emulator.opcodeStepTable = OpcodeStepTableFDCB;
        emulator.address = emulator.PC;
        emulator.PC += 0x01;
        onActionRequired(ActionRequired.MemoryRead, emulator.address, emulator.data);
        emulator.latch = emulator.data;
        emulator.address = emulator.PC;
        emulator.PC += 0x01;
        onActionRequired(ActionRequired.MemoryRead, emulator.address, emulator.data);
        ushort nextInstruction3120 = 65535;
        nextInstruction3120 = Unsafe.Add(ref MemoryMarshal.GetArrayDataReference(emulator.opcodeStepTable), emulator.data);
        emulator.opcodeStepTable = OpcodeStepTableNoPrefix;
        if (nextInstruction3120 != 65535)
        {
            return 6 + emulator.ExecuteDecodedInstruction(nextInstruction3120, onActionRequired);
        }

        return 6;
    }

