    // RLC (IY + d), B
    private static int RLC_IY_plus_d_B(Z80InstructionEmulator emulator, Action<ActionRequired, ushort, byte> onActionRequired)
    {
        emulator.WZ = (ushort)(emulator.IY + (sbyte)emulator.latch);
        emulator.address = emulator.WZ;
        onActionRequired(ActionRequired.MemoryRead, emulator.address, emulator.data);
        var temp = emulator.data;
        emulator.data = (byte)(emulator.data << 0x01 | emulator.data >> 0x07);
        emulator.B = emulator.data;

        // Update flags.
        // Reset N and H.
        int flags = emulator.data & 0b10101000; // Copy flag.X, flag.Y and S from data.
        flags |= ((temp) >> 7) & 1; // Set C if (temp & 0x80) == 0x80 is true.
        flags |= ((~BitOperations.PopCount(emulator.data) & 0b00000001)) << 2; // Set PV if even_parity(data) is true.
        flags |= (Unsafe.BitCast<bool, byte>(emulator.data == 0)) << 6; // Set Z if is_zero(data) is true.
        emulator.F = (byte)flags;
        onActionRequired(ActionRequired.MemoryWrite, emulator.address, emulator.data);
        return emulator.CompleteInstruction(true, 9);
    }

